int sma_hysteresis_pid(float sp,float pv,float dt,float wire_temp,float* intg,float* lastE){
  if(wire_temp>120.0f){*intg=0.0f;*lastE=0.0f;return 0;}
  bool heating=(sp>pv);
  float kp=heating?4.0f:1.8f;
  float ki=heating?0.25f:0.08f;
  float kd=heating?0.4f:0.15f;
  return pid_heater_control(sp,pv,dt,kp,ki,kd,intg,lastE);
}
